			Value: "state123",
		}
		httpReq.AddCookie(stateCookie)

		// Add token cookie
		tokenCookie := &http.Cookie{
			Name:  "flipt_client_token",
			Value: "token456",
		}
		httpReq.AddCookie(tokenCookie)

		// Call ForwardCookies
		md := method.ForwardCookies(context.Background(), httpReq)

		// Due to the bug at internal/server/authn/method/http.go:49,
		// the function uses md[stateCookieKey] for both cookies
		// This means:
		// 1. The state cookie is set: md["flipt_client_state"] = "state123"
		// 2. The token cookie tries to set md["flipt_client_state"] again = "token456"
		// 3. The token value is never properly forwarded in a way the middleware can use

		// The metadata should have the token available as "flipt_client_token"
		// but instead it only has it under "flipt_client_state"
