)

// Regression Tests for Authentication Issues
// ==========================================
//
// This test suite demonstrates two critical authentication bugs in Flipt:
//
// 1. COOKIE-BASED TOKEN EXTRACTION FAILURE
//    Bug Location: internal/server/authn/method/http.go:49 in ForwardCookies()
//    Description: The ForwardCookies function has a bug where it always uses
//                 the stateCookieKey constant instead of the actual key variable
//                 when forwarding cookies as gRPC metadata. This causes the
//                 flipt_client_token cookie to not be properly forwarded to the
//                 authentication middleware.
//    Impact: Browser-based requests that store tokens in HTTP cookies cannot
//            authenticate because the token is not extracted from the cookie.
//    Test Cases: TestRegression_CookieTokenAuthenticationFailure
//
// 2. NO SERVER-LEVEL AUTHENTICATION BYPASS FOR HTTP
//    Bug Location: internal/server/authn/middleware/ (missing HTTP implementation)
//    Description: The SkipsAuthenticationServer interface exists and works for
//                 gRPC servers, allowing them to skip authentication. However,
//                 there is no equivalent mechanism for HTTP endpoints. Internal
//                 servers (like OIDC/OAuth handlers) that should operate without
//                 authentication checks have no way to bypass auth at the HTTP level.
//    Impact: Certain internal endpoints cannot bypass authentication, making it
//            impossible to implement delegated authentication flows that require
//            unauthenticated access to redirect/callback endpoints.
//    Test Cases: TestRegression_ServerSkipAuthenticationNotImplementedForHTTP

// TestRegression_CookieTokenAuthenticationFailure demonstrates that authentication fails
// when a valid client token is stored in an HTTP cookie but not in the Authorization header.
// This is the "browser cookie-based token" issue described in the bug report.
//
// ROOT CAUSE ANALYSIS:
// The bug is located in internal/server/authn/method/http.go at line 49 in the ForwardCookies() function:
//
//   func ForwardCookies(ctx context.Context, req *http.Request) metadata.MD {
//       md := metadata.MD{}
//       for _, key := range []string{stateCookieKey, tokenCookieKey} {
//           if cookie, err := req.Cookie(key); err == nil {
//               md[stateCookieKey] = []string{cookie.Value}  // BUG: Should be md[key], not md[stateCookieKey]!
//           }
//       }
//       return md
//   }
//
// The function iterates over both "flipt_client_state" and "flipt_client_token" keys,
// but always writes to md[stateCookieKey], causing:
// 1. The token cookie value to overwrite the state cookie value in the metadata
// 2. The token to never be accessible under the "flipt_client_token" key
// 3. The gRPC middleware's clientTokenFromMetadata() function to fail to find the token
//
// EXPECTED BEHAVIOR:
// The ForwardCookies function should write to md[key] so that both cookies are properly
// forwarded as separate metadata entries that the gRPC middleware can extract.
//
// IMPACT:
// Any browser-based client sending a valid token in the flipt_client_token cookie
// will fail authentication unless they also include the token in the Authorization header.
func TestRegression_CookieTokenAuthenticationFailure(t *testing.T) {
	// Create an in-memory authentication store
	authenticator := memory.NewStore()

	// Create a valid client token
	clientToken, storedAuth, err := authenticator.CreateAuthentication(
		context.Background(),
		&authn.CreateAuthenticationRequest{Method: auth.Method_METHOD_TOKEN},
	)
	require.NoError(t, err)
	require.NotNil(t, storedAuth)

	logger := zaptest.NewLogger(t)

	// Test Case 1: Token via Authorization header (Bearer) works
	t.Run("Token_Via_Authorization_Header_Works", func(t *testing.T) {
		ctx := context.Background()
		ctx = metadata.NewIncomingContext(ctx, metadata.MD{
			"Authorization": []string{"Bearer " + clientToken},
		})

		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			return nil, nil
		}

		_, err := authmiddlewaregrpc.ClientTokenAuthenticationInterceptor(logger, authenticator)(
			ctx,
			nil,
			&grpc.UnaryServerInfo{Server: &mockServer{}},
			handler,
		)
		assert.NoError(t, err, "Authorization header with Bearer token should work")
	})

	// Test Case 2: Token via grpcgateway-cookie metadata header works
	// (This is the current workaround for gRPC gateway requests)
	t.Run("Token_Via_gRPCGateway_Cookie_Metadata_Works", func(t *testing.T) {
		ctx := context.Background()
		ctx = metadata.NewIncomingContext(ctx, metadata.MD{
			"grpcgateway-cookie": []string{"flipt_client_token=" + clientToken},
		})

		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			return nil, nil
		}

		_, err := authmiddlewaregrpc.ClientTokenAuthenticationInterceptor(logger, authenticator)(
			ctx,
			nil,
			&grpc.UnaryServerInfo{Server: &mockServer{}},
			handler,
		)
		assert.NoError(t, err, "grpcgateway-cookie metadata header should work")
	})

	// Test Case 3: Token via standard HTTP Cookie header fails
	// This is the main issue: browsers send cookies via the standard Cookie header,
	// but the current implementation doesn't extract them for gRPC requests
	t.Run("Token_Via_Standard_HTTP_Cookie_Fails", func(t *testing.T) {
		// Simulate an HTTP request with a cookie
		httpReq := httptest.NewRequest(http.MethodPost, "http://localhost/some-endpoint", nil)
		httpReq.Header.Add("Cookie", "flipt_client_token="+clientToken)

		// Use the ForwardCookies function to convert HTTP cookies to gRPC metadata
		// This is what the gRPC gateway should do, but it has a bug
		md := method.ForwardCookies(context.Background(), httpReq)

		// The ForwardCookies function should populate the metadata with the token,
		// but it has a bug where it always uses stateCookieKey instead of the actual key
		ctx := context.Background()
		if len(md) > 0 {
			ctx = metadata.NewIncomingContext(ctx, md)
		}

		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			return nil, nil
		}

		_, err := authmiddlewaregrpc.ClientTokenAuthenticationInterceptor(logger, authenticator)(
			ctx,
			nil,
			&grpc.UnaryServerInfo{Server: &mockServer{}},
			handler,
		)

		// This SHOULD work but currently fails due to the bug in ForwardCookies
		// The bug is at internal/server/authn/method/http.go:49 where it always uses stateCookieKey
		assert.Error(t, err, "Token via standard HTTP Cookie should be extracted and work, but currently fails due to bug in ForwardCookies")
		assert.Equal(t, codes.Unauthenticated, status.Code(err))
	})

	// Test Case 4: Token extraction bug in ForwardCookies
	// The ForwardCookies function at internal/server/authn/method/http.go:49
	// has a bug where it always uses stateCookieKey instead of the actual key
	t.Run("ForwardCookies_Bug_Always_Uses_StateCookieKey", func(t *testing.T) {
		httpReq := httptest.NewRequest(http.MethodPost, "http://localhost/some-endpoint", nil)
		httpReq.Header.Add("Cookie", "flipt_client_state=state-value")
		httpReq.Header.Add("Cookie", "flipt_client_token="+clientToken)

		md := method.ForwardCookies(context.Background(), httpReq)

		// Check if the token cookie was properly forwarded
		// Due to the bug, we expect this to fail because the function always uses stateCookieKey
		if len(md) > 0 {
			// The bug causes the function to set md[stateCookieKey] for both cookies
			// instead of md[key] for each cookie
			stateCookieValues := md.Get("flipt_client_state")
			tokenCookieValues := md.Get("flipt_client_token")

			// This assertion will reveal the bug:
			// tokenCookieValues should contain the token but it doesn't
			assert.Empty(t, tokenCookieValues, "Bug: flipt_client_token cookie is not properly forwarded due to stateCookieKey bug in ForwardCookies")
		}
	})
}

// TestRegression_ServerSkipAuthenticationNotImplementedForHTTP demonstrates that
// there is no mechanism to skip authentication for specific HTTP server endpoints.
// While the SkipsAuthenticationServer interface exists for gRPC, it's not available for HTTP.
func TestRegression_ServerSkipAuthenticationNotImplementedForHTTP(t *testing.T) {
	authenticator := memory.NewStore()
	logger := zaptest.NewLogger(t)

	// Create a server that claims it should skip authentication
	skipAuthServer := &mockSkipAuthServer{skipsAuth: true}

	// Test Case 1: gRPC-level skip authentication works
	t.Run("Skip_Authentication_Works_For_gRPC", func(t *testing.T) {
		ctx := context.Background()
		ctx = metadata.NewIncomingContext(ctx, metadata.MD{})

		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			return nil, nil
		}

		_, err := authmiddlewaregrpc.ClientTokenAuthenticationInterceptor(logger, authenticator)(
			ctx,
			nil,
			&grpc.UnaryServerInfo{Server: skipAuthServer},
			handler,
		)
		assert.NoError(t, err, "gRPC server with SkipsAuthenticationServer interface should skip auth")
	})

	// Test Case 2: HTTP-level skip authentication doesn't exist
	// The HTTP middleware doesn't have a way to skip authentication for specific servers
	t.Run("Skip_Authentication_Not_Implemented_For_HTTP", func(t *testing.T) {
		// Create an HTTP request without authentication
		httpReq := httptest.NewRequest(http.MethodPost, "http://localhost/auth/v1/some-endpoint", nil)
		w := httptest.NewRecorder()

		// The HTTP error handler in authmiddlewarehttp.ErrorHandler doesn't check
		// if the server should skip authentication - it only clears cookies on errors
		middleware := authmiddlewarehttp.NewHTTPMiddleware(config.AuthenticationSession{
			Domain: "localhost",
		})

		// Simulate an unauthenticated error
		err := status.Error(codes.Unauthenticated, "request was not authenticated")
		middleware.ErrorHandler(context.Background(), nil, nil, w, httpReq, err)

		// The error handler will clear cookies but there's no way to skip auth for specific servers
		// This is a design gap: there's no HTTP-level mechanism to bypass authentication
		assert.NotNil(t, middleware, "No HTTP-level mechanism exists to skip authentication for servers")
	})

	// Test Case 3: Expired token handling
	// Ensure expired tokens are properly rejected
	t.Run("Expired_Token_Rejected", func(t *testing.T) {
		expiredToken, _, err := authenticator.CreateAuthentication(
			context.Background(),
			&authn.CreateAuthenticationRequest{
				Method:    auth.Method_METHOD_TOKEN,
				ExpiresAt: timestamppb.New(time.Now().UTC().Add(-time.Hour)),
			},
		)
		require.NoError(t, err)

		ctx := context.Background()
		ctx = metadata.NewIncomingContext(ctx, metadata.MD{
			"Authorization": []string{"Bearer " + expiredToken},
		})

		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			return nil, nil
		}

		_, err = authmiddlewaregrpc.ClientTokenAuthenticationInterceptor(logger, authenticator)(
			ctx,
			nil,
			&grpc.UnaryServerInfo{Server: &mockServer{}},
			handler,
		)
		assert.Error(t, err, "Expired tokens should be rejected")
		assert.Equal(t, codes.Unauthenticated, status.Code(err))
	})
}

// TestRegression_AuthenticationIntegration tests the integration of
// cookie-based authentication with HTTP requests
func TestRegression_AuthenticationIntegration(t *testing.T) {
	authenticator := memory.NewStore()
	logger := zaptest.NewLogger(t)

	// Create a valid client token
	clientToken, _, err := authenticator.CreateAuthentication(
		context.Background(),
		&authn.CreateAuthenticationRequest{Method: auth.Method_METHOD_TOKEN},
	)
	require.NoError(t, err)

	t.Run("HTTP_Request_With_Cookie_Should_Be_Authenticated", func(t *testing.T) {
		// Create an HTTP request with the token in a cookie (like a browser would)
		httpReq := httptest.NewRequest(http.MethodPost, "http://localhost/api/v1/evaluation", nil)
		httpReq.Header.Add("Cookie", "flipt_client_token="+clientToken)

		// Forward cookies to gRPC metadata (this should work but has a bug)
		md := method.ForwardCookies(context.Background(), httpReq)

		ctx := context.Background()
		if len(md) > 0 {
			ctx = metadata.NewIncomingContext(ctx, md)
		}

		// This request should be authenticated, but it's not due to the ForwardCookies bug
		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			// In a real scenario, this would be authenticated
			return nil, nil
		}

		_, err := authmiddlewaregrpc.ClientTokenAuthenticationInterceptor(logger, authenticator)(
			ctx,
			nil,
			&grpc.UnaryServerInfo{Server: &mockServer{}},
			handler,
		)

		assert.Error(t, err, "HTTP request with cookie token should be authenticated but fails due to ForwardCookies bug")
	})

	t.Run("Multiple_Cookies_In_Request", func(t *testing.T) {
		// Create an HTTP request with multiple cookies
		httpReq := httptest.NewRequest(http.MethodPost, "http://localhost/api/v1/evaluation", nil)
		httpReq.Header.Add("Cookie", "flipt_client_state=some-state")
		httpReq.Header.Add("Cookie", "flipt_client_token="+clientToken)
		httpReq.Header.Add("Cookie", "session=123456")

		md := method.ForwardCookies(context.Background(), httpReq)

		// Due to the bug, the function doesn't properly handle multiple cookies
		// It should extract both state and token, but the bug prevents this
		assert.NotNil(t, md, "ForwardCookies should handle multiple cookies properly")
	})
}

