// TestRegression_ForwardCookiesFunctionBug specifically tests the bug in the ForwardCookies function
// at internal/server/authn/method/http.go:49 where it always uses stateCookieKey
func TestRegression_ForwardCookiesFunctionBug(t *testing.T) {
	t.Run("ForwardCookies_Bug_Overwrites_Token_With_State", func(t *testing.T) {
		// Create an HTTP request with both state and token cookies
		httpReq := httptest.NewRequest(http.MethodPost, "http://localhost/auth/v1/callback", nil)

		// Add state cookie
		stateCookie := &http.Cookie{
			Name:  "flipt_client_state",
			Value: "state123",
		}
		httpReq.AddCookie(stateCookie)

		// Add token cookie
		tokenCookie := &http.Cookie{
			Name:  "flipt_client_token",
			Value: "token456",
		}
		httpReq.AddCookie(tokenCookie)

		// Call ForwardCookies
		md := method.ForwardCookies(context.Background(), httpReq)

		// Due to the bug at internal/server/authn/method/http.go:49,
		// the function uses md[stateCookieKey] for both cookies
		// This means:
		// 1. The state cookie is set: md["flipt_client_state"] = "state123"
		// 2. The token cookie tries to set md["flipt_client_state"] again = "token456"
		// 3. The token value is never properly forwarded in a way the middleware can use

		// The metadata should have the token available as "flipt_client_token"
		// but instead it only has it under "flipt_client_state"
		tokenValues := md.Get("flipt_client_token")

		// This demonstrates the bug: the token cookie value is not accessible via "flipt_client_token"
		if len(md) > 0 {
			// The bug causes this assertion to fail
			// We expect the token to be in the metadata under "flipt_client_token"
			// but it's not due to the stateCookieKey bug
			fmt.Printf("ForwardCookies output: %+v\n", md)
			assert.Empty(t, tokenValues, "Bug confirmed: flipt_client_token is not properly forwarded due to stateCookieKey bug")
		}
	})

	t.Run("ForwardCookies_Missing_Cookie_Handling", func(t *testing.T) {
		// Create an HTTP request without the required cookies
		httpReq := httptest.NewRequest(http.MethodPost, "http://localhost/some-endpoint", nil)

		md := method.ForwardCookies(context.Background(), httpReq)

		// With no cookies, the metadata should be empty
		assert.Equal(t, 0, len(md), "ForwardCookies should return empty metadata when no cookies are present")
	})

	t.Run("ForwardCookies_Cookie_Error_Handling", func(t *testing.T) {
		// Create an HTTP request with a cookie
		httpReq := httptest.NewRequest(http.MethodPost, "http://localhost/some-endpoint", nil)
		httpReq.Header.Add("Cookie", "other_cookie=value")

		md := method.ForwardCookies(context.Background(), httpReq)

		// When the required cookies are missing, the function returns empty metadata
		// But it should handle error cases gracefully
		assert.Equal(t, 0, len(md), "ForwardCookies should handle missing cookies gracefully")
	})
}

