// TestRegression_ServerSkipAuthenticationNotImplementedForHTTP demonstrates that
// there is no mechanism to skip authentication for specific HTTP server endpoints.
// While the SkipsAuthenticationServer interface exists for gRPC, it's not available for HTTP.
//
// ROOT CAUSE ANALYSIS:
// The gRPC middleware (internal/server/authn/middleware/grpc/middleware.go) has a
// SkipsAuthenticationServer interface (lines 112-115) and an AuthenticationRequiredInterceptor
// (lines 119-138) that checks if a server implements this interface and skips auth if it does.
//
// However, the HTTP middleware (internal/server/authn/middleware/http/middleware.go)
// doesn't have any equivalent mechanism. The HTTP middleware only handles:
// 1. Clearing cookies on logout (Handler method)
// 2. Clearing cookies on authentication errors (ErrorHandler method)
//
// There is NO HTTP-level implementation of:
// - Skipping authentication for specific servers
// - Allowing certain endpoints to operate without authentication
// - Implementing an HTTP equivalent of SkipsAuthenticationServer
//
// IMPACT:
// Internal servers (like OIDC/GitHub/Kubernetes authentication method servers) that need
// to operate without authentication checks cannot bypass the authentication middleware at
// the HTTP level. This makes it impossible to implement certain delegated authentication
// flows that require unauthenticated access to callback/redirect endpoints.
//
// The workaround is to ensure SessionEnabled() is false, which prevents the ForwardCookies
// function from being used, but this affects all HTTP authentication flow, not just the
// internal servers that should skip auth.
func TestRegression_ServerSkipAuthenticationNotImplementedForHTTP(t *testing.T) {
	authenticator := memory.NewStore()
	logger := zaptest.NewLogger(t)

	// Create a server that claims it should skip authentication
	skipAuthServer := &mockSkipAuthServer{skipsAuth: true}

	// Test Case 1: gRPC-level skip authentication works
	t.Run("Skip_Authentication_Works_For_gRPC", func(t *testing.T) {
		ctx := context.Background()
		ctx = metadata.NewIncomingContext(ctx, metadata.MD{})

		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			return nil, nil
		}

		_, err := authmiddlewaregrpc.ClientTokenAuthenticationInterceptor(logger, authenticator)(
			ctx,
			nil,
			&grpc.UnaryServerInfo{Server: skipAuthServer},
			handler,
		)
		assert.NoError(t, err, "gRPC server with SkipsAuthenticationServer interface should skip auth")
	})

	// Test Case 2: HTTP-level skip authentication doesn't exist
	// The HTTP middleware doesn't have a way to skip authentication for specific servers
	t.Run("Skip_Authentication_Not_Implemented_For_HTTP", func(t *testing.T) {
		// Create an HTTP request without authentication
		httpReq := httptest.NewRequest(http.MethodPost, "http://localhost/auth/v1/some-endpoint", nil)
		w := httptest.NewRecorder()

		// The HTTP error handler in authmiddlewarehttp.ErrorHandler doesn't check
		// if the server should skip authentication - it only clears cookies on errors
		middleware := authmiddlewarehttp.NewHTTPMiddleware(config.AuthenticationSession{
			Domain: "localhost",
		})

		// Simulate an unauthenticated error
		err := status.Error(codes.Unauthenticated, "request was not authenticated")
		middleware.ErrorHandler(context.Background(), nil, nil, w, httpReq, err)

		// The error handler will clear cookies but there's no way to skip auth for specific servers
		// This is a design gap: there's no HTTP-level mechanism to bypass authentication
		assert.NotNil(t, middleware, "No HTTP-level mechanism exists to skip authentication for servers")
	})

	// Test Case 3: Expired token handling
	// Ensure expired tokens are properly rejected
	t.Run("Expired_Token_Rejected", func(t *testing.T) {
		expiredToken, _, err := authenticator.CreateAuthentication(
			context.Background(),
			&authn.CreateAuthenticationRequest{
				Method:    auth.Method_METHOD_TOKEN,
				ExpiresAt: timestamppb.New(time.Now().UTC().Add(-time.Hour)),
			},
		)
		require.NoError(t, err)

		ctx := context.Background()
		ctx = metadata.NewIncomingContext(ctx, metadata.MD{
			"Authorization": []string{"Bearer " + expiredToken},
		})

		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			return nil, nil
		}

		_, err = authmiddlewaregrpc.ClientTokenAuthenticationInterceptor(logger, authenticator)(
			ctx,
			nil,
			&grpc.UnaryServerInfo{Server: &mockServer{}},
			handler,
		)
		assert.Error(t, err, "Expired tokens should be rejected")
		assert.Equal(t, codes.Unauthenticated, status.Code(err))
	})
}

