		ctx = metadata.NewIncomingContext(ctx, metadata.MD{})

		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			return nil, nil
		}

		_, err := authmiddlewaregrpc.ClientTokenAuthenticationInterceptor(logger, authenticator)(
			ctx,
			nil,
			&grpc.UnaryServerInfo{Server: skipAuthServer},
			handler,
		)
		assert.NoError(t, err, "gRPC server with SkipsAuthenticationServer interface should skip auth")
	})

	// Test Case 2: HTTP-level skip authentication doesn't exist
	// The HTTP middleware doesn't have a way to skip authentication for specific servers
	t.Run("Skip_Authentication_Not_Implemented_For_HTTP", func(t *testing.T) {
		// Create an HTTP request without authentication
		httpReq := httptest.NewRequest(http.MethodPost, "http://localhost/auth/v1/some-endpoint", nil)
		w := httptest.NewRecorder()

		// The HTTP error handler in authmiddlewarehttp.ErrorHandler doesn't check
		// if the server should skip authentication - it only clears cookies on errors
		middleware := authmiddlewarehttp.NewHTTPMiddleware(config.AuthenticationSession{
			Domain: "localhost",
		})

		// Simulate an unauthenticated error
		err := status.Error(codes.Unauthenticated, "request was not authenticated")
		middleware.ErrorHandler(context.Background(), nil, nil, w, httpReq, err)

		// The error handler will clear cookies but there's no way to skip auth for specific servers
		// This is a design gap: there's no HTTP-level mechanism to bypass authentication
		assert.NotNil(t, middleware, "No HTTP-level mechanism exists to skip authentication for servers")
	})

	// Test Case 3: Expired token handling
	// Ensure expired tokens are properly rejected
	t.Run("Expired_Token_Rejected", func(t *testing.T) {
		expiredToken, _, err := authenticator.CreateAuthentication(
			context.Background(),
			&authn.CreateAuthenticationRequest{
				Method:    auth.Method_METHOD_TOKEN,
				ExpiresAt: timestamppb.New(time.Now().UTC().Add(-time.Hour)),
			},
		)
		require.NoError(t, err)

		ctx := context.Background()
		ctx = metadata.NewIncomingContext(ctx, metadata.MD{
			"Authorization": []string{"Bearer " + expiredToken},
		})

		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			return nil, nil
		}

		_, err = authmiddlewaregrpc.ClientTokenAuthenticationInterceptor(logger, authenticator)(
			ctx,
			nil,
			&grpc.UnaryServerInfo{Server: &mockServer{}},
			handler,
		)
		assert.Error(t, err, "Expired tokens should be rejected")
		assert.Equal(t, codes.Unauthenticated, status.Code(err))
	})
}

// TestRegression_AuthenticationIntegration tests the integration of
// cookie-based authentication with HTTP requests
func TestRegression_AuthenticationIntegration(t *testing.T) {
	authenticator := memory.NewStore()
	logger := zaptest.NewLogger(t)

	// Create a valid client token
	clientToken, _, err := authenticator.CreateAuthentication(
		context.Background(),
		&authn.CreateAuthenticationRequest{Method: auth.Method_METHOD_TOKEN},
	)
	require.NoError(t, err)

	t.Run("HTTP_Request_With_Cookie_Should_Be_Authenticated", func(t *testing.T) {
		// Create an HTTP request with the token in a cookie (like a browser would)
		httpReq := httptest.NewRequest(http.MethodPost, "http://localhost/api/v1/evaluation", nil)
		httpReq.Header.Add("Cookie", "flipt_client_token="+clientToken)

		// Forward cookies to gRPC metadata (this should work but has a bug)
		md := method.ForwardCookies(context.Background(), httpReq)

		ctx := context.Background()
		if len(md) > 0 {
			ctx = metadata.NewIncomingContext(ctx, md)
		}

		// This request should be authenticated, but it's not due to the ForwardCookies bug
		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			// In a real scenario, this would be authenticated
			return nil, nil
		}

		_, err := authmiddlewaregrpc.ClientTokenAuthenticationInterceptor(logger, authenticator)(
			ctx,
			nil,
			&grpc.UnaryServerInfo{Server: &mockServer{}},
			handler,
		)

		assert.Error(t, err, "HTTP request with cookie token should be authenticated but fails due to ForwardCookies bug")
	})

	t.Run("Multiple_Cookies_In_Request", func(t *testing.T) {
		// Create an HTTP request with multiple cookies
		httpReq := httptest.NewRequest(http.MethodPost, "http://localhost/api/v1/evaluation", nil)
		httpReq.Header.Add("Cookie", "flipt_client_state=some-state")
		httpReq.Header.Add("Cookie", "flipt_client_token="+clientToken)
		httpReq.Header.Add("Cookie", "session=123456")

		md := method.ForwardCookies(context.Background(), httpReq)

		// Due to the bug, the function doesn't properly handle multiple cookies
		// It should extract both state and token, but the bug prevents this
		assert.NotNil(t, md, "ForwardCookies should handle multiple cookies properly")
	})
}

